package ua.university.sms.service;
import org.springframework.stereotype.Service;import ua.university.sms.exception.NotFoundException;import ua.university.sms.model.dto.TeacherDtos.*;import ua.university.sms.model.entity.Teacher;import ua.university.sms.repository.TeacherRepository;import java.util.*;
@Service public class TeacherService{private final TeacherRepository repo;public TeacherService(TeacherRepository repo){this.repo=repo;}public Response create(Request r){Teacher t=new Teacher();apply(t,r);return dto(repo.save(t));}public Response get(Long id){return dto(find(id));}public List<Response> list(){return repo.findAll().stream().map(this::dto).toList();}public Response update(Long id,Request r){Teacher t=find(id);apply(t,r);return dto(repo.save(t));}public void delete(Long id){repo.delete(find(id));}Teacher find(Long id){return repo.findById(id).orElseThrow(()->new NotFoundException("Teacher not found: "+id));}private void apply(Teacher t,Request r){t.setFullName(r.fullName());t.setEmail(r.email());t.setDepartment(r.department());}private Response dto(Teacher t){return new Response(t.getId(),t.getFullName(),t.getEmail(),t.getDepartment());}}
